INSERT INTO GOAL_LIST (
      USER_ID
    , GOAL_DATE
    , TITLE
    , CONTENT
    , ACHIEVE_RATE
    , STATUS_YN
    , INSERT_ID
) 
VALUES (
      #{userId}
    , #{goalDate}
    , #{title}
    , #{content}
    , 0
    , 'N'
    , #{insertId}
)

mapper.update:
UPDATE GOAL_LIST
SET   CONTENT      = #{content}
    , ACHIEVE_RATE = #{achieveRate}
    , STATUS_YN    = 'Y'
    , UPDATE_ID    = #{updateId}
    , UPDATE_DTS   = NOW()
WHERE GOAL_SEQ     = #{goalSeq}
